namespace BgControls.Windows.Input.Touch;/// <summary>/// 捏合手势辅助类，用于管理多个触控点并计算缩放因子./// </summary>internal class PinchHelper{    private UIElement element;    private List<PinchInfo> infosList;    private double initialPinchDistance;    private GestureState state;    private GestureDeactivationToken? gestureToken;    /// <summary>    /// Initializes a new instance of the <see cref="PinchHelper"/> class.    /// </summary>    /// <param name="element">关联的 UI 元素.</param>    public PinchHelper(UIElement element)    {        // 验证参数是否为空.        ArgumentNullException.ThrowIfNull(element, nameof(element));        this.element = element;        this.infosList = new List<PinchInfo>();    }    /// <summary>    /// 检查指定的触控 ID 是否已关联.    /// </summary>    /// <param name="touchId">触控 ID.</param>    /// <returns>如果已关联则返回 true; 否则返回 false.</returns>    public bool HasAssociatedTouchId(int touchId)    {        return this.infosList.Any(info => info.TouchId == touchId);    }    /// <summary>    /// 检查是否可以关联新的触控 ID（捏合手势最多支持两个点）.    /// </summary>    /// <returns>如果可以关联则返回 true; 否则返回 false.</returns>    public bool CanAssociateTouchId()    {        return this.infosList.Count <= 1;    }    /// <summary>    /// 关联指定的触控 ID 并初始化其位置信息.    /// </summary>    /// <param name="touchId">触控 ID.</param>    /// <param name="touchDownPosition">按下时的坐标.</param>    /// <param name="args">触控事件参数.</param>    public void AssociateTouchId(int touchId, Point touchDownPosition, BgControls.Windows.Input.Touch.TouchEventArgs args)    {        // 校验输入参数.        ArgumentNullException.ThrowIfNull(args, nameof(args));        if (!this.CanAssociateTouchId())        {            throw new InvalidOperationException("Cannot associate more than two touchIds.");        }        // 创建新的捏合信息实例并加入列表.        PinchInfo item = new PinchInfo(this.element, touchId, touchDownPosition, args, this.OnLostTouchCapture);        this.infosList.Add(item);    }    /// <summary>    /// 处理触控移动事件并根据状态触发捏合逻辑.    /// </summary>    /// <param name="args">手势识别器事件参数.</param>    public void OnTouchMove(GestureRecognizerEventArgs args)    {        ArgumentNullException.ThrowIfNull(args, nameof(args));        PinchInfo? pinchInfo = this.TryGetPinchInfo(args.TouchId);        if (pinchInfo == null)        {            return;        }        // 更新当前触控点的位置和参数.        pinchInfo.LastTouchMovePosition = args.Position;        pinchInfo.TouchEventArgs = args.TouchEventArgs;        if (this.infosList.Count == 1)        {            // 如果只有一个点，则将当前点设为枢轴点.            pinchInfo.PivotPosition = pinchInfo.LastTouchMovePosition;        }        else if (this.state == GestureState.Active)        {            // 如果手势已激活且有两个点，处理捏合位移.            this.HandlePinching(out bool handled);            args.TouchEventArgs.Handled = handled;            args.Handled = true;        }        else        {            // 尝试触发捏合手势启动判定.            this.HandlePinchStarting(args.TouchEventArgs, pinchInfo, args.Position, out bool gestureHandled);            args.Handled = gestureHandled;        }    }    /// <summary>    /// 处理触控抬起事件.    /// </summary>    /// <param name="args">手势识别器事件参数.</param>    public void OnTouchUp(GestureRecognizerEventArgs args)    {        ArgumentNullException.ThrowIfNull(args, nameof(args));        PinchInfo? pinchInfo = this.TryGetPinchInfo(args.TouchId);        if (pinchInfo == null)        {            return;        }        pinchInfo.TouchEventArgs = args.TouchEventArgs;        // 处理捏合结束流程.        this.HandlePinchFinishing(pinchInfo, args.TouchEventArgs.TouchDevice, false, out bool handled, out bool gestureHandled);        args.TouchEventArgs.Handled = handled;        args.Handled = gestureHandled;    }    /// <summary>    /// 处理触控离开事件.    /// </summary>    /// <param name="args">手势识别器事件参数.</param>    public void OnTouchLeave(GestureRecognizerEventArgs args)    {        ArgumentNullException.ThrowIfNull(args, nameof(args));        PinchInfo? info = this.TryGetPinchInfo(args.TouchId);        if (info == null)        {            return;        }        // 尝试捕获触控以维持手势，否则结束.        this.HandlePinchFinishing(info, args.TouchEventArgs.TouchDevice, true, out bool handled, out _);    }    /// <summary>    /// 停止当前手势并释放资源.    /// </summary>    public void CeaseGesture()    {        this.HandlePinchFinishing(null, null, false, out bool _, out _);    }    /// <summary>    /// 处理正在进行的捏合缩放计算.    /// </summary>    private void HandlePinching(out bool handled)    {        // 计算两个触控点之间的当前距离.        double currentDistance = MathUtilities.CalculateDistance(this.infosList[0].LastTouchMovePosition, this.infosList[1].LastTouchMovePosition);        // 计算缩放因子（当前距离 / 初始距离）.        double factor = currentDistance / this.initialPinchDistance;        TouchManager.RaisePinchEvent(this.element, this.infosList[0].TouchEventArgs, this.infosList[1].TouchEventArgs, factor, out handled);    }    /// <summary>    /// 判定并尝试启动捏合手势.    /// </summary>    private void HandlePinchStarting(BgControls.Windows.Input.Touch.TouchEventArgs eventArgs, PinchInfo info, Point position, out bool gestureHandled)    {        // 计算移动距离是否超过启动阈值.        double moveDistance = MathUtilities.CalculateDistance(info.PivotPosition, position);        bool isDistanceMet = moveDistance > TouchManager.PinchStartDistance;        if (isDistanceMet && GestureManager.CanActivateGesture(this.element, TouchManager.PinchGestureName))        {            this.state = GestureState.Active;            // 激活手势并设置强制结束的回调.            this.gestureToken = GestureManager.ActivateGesture(this.element, TouchManager.PinchGestureName, this.CeaseGesture);            // 记录捏合开始时的初始距离.            this.initialPinchDistance = MathUtilities.CalculateDistance(this.infosList[0].LastTouchMovePosition, this.infosList[1].LastTouchMovePosition);            TouchManager.RaisePinchStartedEvent(this.element, this.infosList[0].TouchEventArgs, this.infosList[1].TouchEventArgs, out bool handled);            eventArgs.Handled = handled;            gestureHandled = true;        }        else        {            gestureHandled = false;        }    }    /// <summary>    /// 处理捏合手势的结束或状态回退逻辑.    /// </summary>    private void HandlePinchFinishing(PinchInfo? info, TouchDevice? touchDevice, bool tryCaptureTouch, out bool handled, out bool gestureHandled)    {        if (this.state == GestureState.Active)        {            // 如果手势已激活，尝试通过捕获触控来延长手势，或者直接结束.            if (tryCaptureTouch && info != null && touchDevice != null && info.TryCaptureTouch(touchDevice))            {                handled = false;                gestureHandled = true;            }            else            {                this.FinishPinch(info, out handled);                gestureHandled = true;            }        }        else        {            // 手势未激活时，仅释放对应的触控记录.            this.ReleasePinchInfoSmart(info);            handled = false;            gestureHandled = false;        }    }    /// <summary>    /// 执行捏合手势的完成清理并触发结束事件.    /// </summary>    private void FinishPinch(PinchInfo? info, out bool handled)    {        this.state = GestureState.Finished;        PinchInfo firstInfo = this.infosList[0];        PinchInfo secondInfo = this.infosList[1];        this.ReleasePinchInfoSmart(info);        // 停用并清除手势 Token.        if (this.gestureToken != null)        {            this.gestureToken.DeactivateGesture();            this.gestureToken = null;        }        double finalDistance = MathUtilities.CalculateDistance(firstInfo.LastTouchMovePosition, secondInfo.LastTouchMovePosition);        double finalFactor = finalDistance / this.initialPinchDistance;        TouchManager.RaisePinchFinishedEvent(this.element, firstInfo.TouchEventArgs, secondInfo.TouchEventArgs, finalFactor, out handled);    }    /// <summary>    /// 响应丢失触控捕获时的处理逻辑.    /// </summary>    private void OnLostTouchCapture(PinchInfo info, TouchDevice touchDevice)    {        this.HandlePinchFinishing(info, touchDevice, false, out _, out _);    }    /// <summary>    /// 尝试根据触控 ID 获取对应的捏合信息.    /// </summary>    private PinchInfo? TryGetPinchInfo(int touchId)    {        return this.infosList.FirstOrDefault(i => i.TouchId == touchId);    }    /// <summary>    /// 智能释放触控信息（如果传入为空则释放所有记录）.    /// </summary>    private void ReleasePinchInfoSmart(PinchInfo? info)    {        if (info != null)        {            this.ReleasePinchInfo(info);            return;        }        // 复制列表以安全地遍历并删除.        List<PinchInfo> snapshot = new List<PinchInfo>(this.infosList);        foreach (PinchInfo item in snapshot)        {            this.ReleasePinchInfo(item);        }    }    /// <summary>    /// 释放单个触控信息及其对应的捕获资源.    /// </summary>    private void ReleasePinchInfo(PinchInfo info)    {        info.ReleaseTouchCapture();        this.infosList.Remove(info);        this.RecycleHelper();    }    /// <summary>    /// 回收并重置辅助类状态.    /// </summary>    private void RecycleHelper()    {        // 如果仅剩一个点，则将其设为新的枢轴参考点.        if (this.infosList.Count == 1)        {            this.infosList[0].PivotPosition = this.infosList[0].LastTouchMovePosition;        }    }}